const express = require('express');
const crypto = require('crypto');
const redis = require('redis');
const bcrypt = require('bcrypt');
const { promisify } = require('util');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const redisClient = redis.createClient({
  host: 'localhost',
  port: 6379
});

const getAsync = promisify(redisClient.get).bind(redisClient);
const setAsync = promisify(redisClient.set).bind(redisClient);
const delAsync = promisify(redisClient.del).bind(redisClient);
const saddAsync = promisify(redisClient.sadd).bind(redisClient);
const sismemberAsync = promisify(redisClient.sismember).bind(redisClient);
const sremAsync = promisify(redisClient.srem).bind(redisClient);

const ACCESS_TOKEN_EXPIRY = 3600;
const REFRESH_TOKEN_EXPIRY = 31536000;
const MAX_REFRESH_TOKEN_USES = 100;
const RATE_LIMIT_WINDOW = 300;
const MAX_REQUESTS_PER_WINDOW = 10;

const clients = {
  'client123': {
    clientSecret: '$2b$10$abcdefghijklmnopqrstuvwxyz123456',
    redirectUris: ['http://localhost:3001/callback'],
    allowedScopes: ['read', 'write']
  }
};

const users = {
  'user1': {
    passwordHash: '$2b$10$abcdefghijklmnopqrstuvwxyz123456',
    userId: 'user1'
  }
};

function generateSecureToken(length = 64) {
  return crypto.randomBytes(length).toString('base64url');
}

function generateTokenFingerprint() {
  return crypto.randomBytes(32).toString('base64url');
}

function hashToken(token) {
  return crypto.createHash('sha256').update(token).digest('hex');
}

async function checkRateLimit(identifier) {
  const key = `ratelimit:${identifier}`;
  const current = await getAsync(key);
  
  if (current && parseInt(current) >= MAX_REQUESTS_PER_WINDOW) {
    return false;
  }
  
  if (!current) {
    await setAsync(key, '1', 'EX', RATE_LIMIT_WINDOW);
  } else {
    await redisClient.incr(key);
  }
  
  return true;
}

async function validateClient(clientId, clientSecret) {
  const client = clients[clientId];
  if (!client) return null;
  
  const isValid = await bcrypt.compare(clientSecret, client.clientSecret);
  return isValid ? client : null;
}

async function storeAuthorizationCode(code, data) {
  const hashedCode = hashToken(code);
  await setAsync(`authcode:${hashedCode}`, JSON.stringify(data), 'EX', 600);
}

async function getAuthorizationCode(code) {
  const hashedCode = hashToken(code);
  const data = await getAsync(`authcode:${hashedCode}`);
  if (data) {
    await delAsync(`authcode:${hashedCode}`);
    return JSON.parse(data);
  }
  return null;
}

async function storeAccessToken(token, data) {
  const hashedToken = hashToken(token);
  await setAsync(`access:${hashedToken}`, JSON.stringify(data), 'EX', ACCESS_TOKEN_EXPIRY);
}

async function storeRefreshToken(token, data) {
  const hashedToken = hashToken(token);
  const tokenData = {
    ...data,
    useCount: 0,
    createdAt: Date.now(),
    lastUsed: Date.now()
  };
  await setAsync(`refresh:${hashedToken}`, JSON.stringify(tokenData), 'EX', REFRESH_TOKEN_EXPIRY);
}

async function getRefreshToken(token) {
  const hashedToken = hashToken(token);
  const data = await getAsync(`refresh:${hashedToken}`);
  return data ? JSON.parse(data) : null;
}

async function updateRefreshTokenUsage(token, tokenData) {
  const hashedToken = hashToken(token);
  tokenData.useCount++;
  tokenData.lastUsed = Date.now();
  
  const remainingTTL = REFRESH_TOKEN_EXPIRY - Math.floor((Date.now() - tokenData.createdAt) / 1000);
  await setAsync(`refresh:${hashedToken}`, JSON.stringify(tokenData), 'EX', remainingTTL);
}

async function revokeRefreshToken(token) {
  const hashedToken = hashToken(token);
  await delAsync(`refresh:${hashedToken}`);
}

async function isRefreshTokenRevoked(token) {
  const hashedToken = hashToken(token);
  return await sismemberAsync('revoked_tokens', hashedToken);
}

async function addToRevokedList(token) {
  const hashedToken = hashToken(token);
  await saddAsync('revoked_tokens', hashedToken);
  await redisClient.expire('revoked_tokens', REFRESH_TOKEN_EXPIRY);
}

app.get('/authorize', (req, res) => {
  const { client_id, redirect_uri, response_type, scope, state } = req.query;
  
  if (response_type !== 'code') {
    return res.status(400).json({ error: 'unsupported_response_type' });
  }
  
  const client = clients[client_id];
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }
  
  if (!client.redirectUris.includes(redirect_uri)) {
    return res.status(400).json({ error: 'invalid_redirect_uri' });
  }
  
  const requestedScopes = scope ? scope.split(' ') : [];
  const invalidScopes = requestedScopes.filter(s => !client.allowedScopes.includes(s));
  if (invalidScopes.length > 0) {
    return res.status(400).json({ error: 'invalid_scope' });
  }
  
  res.send(`
    <html>
      <body>
        <h2>Authorization Request</h2>
        <p>Client ${client_id} is requesting access with scopes: ${scope || 'default'}</p>
        <form method="POST" action="/authorize">
          <input type="hidden" name="client_id" value="${client_id}" />
          <input type="hidden" name="redirect_uri" value="${redirect_uri}" />
          <input type="hidden" name="scope" value="${scope || ''}" />
          <input type="hidden" name="state" value="${state || ''}" />
          <label>Username: <input type="text" name="username" required /></label><br/>
          <label>Password: <input type="password" name="password" required /></label><br/>
          <button type="submit">Authorize</button>
        </form>
      </body>
    </html>
  `);
});

app.post('/authorize', async (req, res) => {
  const { client_id, redirect_uri, scope, state, username, password } = req.body;
  
  const user = users[username];
  if (!user || !(await bcrypt.compare(password, user.passwordHash))) {
    return res.status(401).json({ error: 'invalid_credentials' });
  }
  
  const authCode = generateSecureToken();
  const codeVerifier = generateSecureToken(32);
  
  await storeAuthorizationCode(authCode, {
    clientId: client_id,
    userId: user.userId,
    redirectUri: redirect_uri,
    scope: scope || '',
    codeVerifier: hashToken(codeVerifier)
  });
  
  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.append('code', authCode);
  if (state) redirectUrl.searchParams.append('state', state);
  
  res.redirect(redirectUrl.toString());
});

app.post('/token', async (req, res) => {
  const { grant_type, code, refresh_token, client_id, client_secret, redirect_uri } = req.body;
  
  const clientIp = req.ip || req.connection.remoteAddress;
  const rateLimitKey = `${client_id}:${clientIp}`;
  
  if (!(await checkRateLimit(rateLimitKey))) {
    return res.status(429).json({ error: 'too_many_requests' });
  }
  
  const client = await validateClient(client_id, client_secret);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  if (grant_type === 'authorization_code') {
    const authData = await getAuthorizationCode(code);
    
    if (!authData || authData.clientId !== client_id || authData.redirectUri !== redirect_uri) {
      return res.status(400).json({ error: 'invalid_grant' });
    }
    
    const accessToken = generateSecureToken();
    const refreshToken = generateSecureToken();
    const fingerprint = generateTokenFingerprint();
    
    await storeAccessToken(accessToken, {
      clientId: client_id,
      userId: authData.userId,
      scope: authData.scope,
      fingerprint: hashToken(fingerprint)
    });
    
    await storeRefreshToken(refreshToken, {
      clientId: client_id,
      userId: authData.userId,
      scope: authData.scope,
      fingerprint: hashToken(fingerprint),
      ipAddress: clientIp,
      userAgent: req.headers['user-agent']
    });
    
    res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: ACCESS_TOKEN_EXPIRY,
      refresh_token: refreshToken,
      scope: authData.scope,
      fingerprint: fingerprint
    });
    
  } else if (grant_type === 'refresh_token') {
    if (await isRefreshTokenRevoked(refresh_token)) {
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Token has been revoked' });
    }
    
    const tokenData = await getRefreshToken(refresh_token);
    
    if (!tokenData || tokenData.clientId !== client_id) {
      await addToRevokedList(refresh_token);
      return res.status(400).json({ error: 'invalid_grant' });
    }
    
    if (tokenData.useCount >= MAX_REFRESH_TOKEN_USES) {
      await revokeRefreshToken(refresh_token);
      await addToRevokedList(refresh_token);
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Token usage limit exceeded' });
    }
    
    const timeSinceCreation = Date.now() - tokenData.createdAt;
    if (timeSinceCreation > REFRESH_TOKEN_EXPIRY * 1000) {
      await revokeRefreshToken(refresh_token);
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Token expired' });
    }
    
    const currentIp = clientIp;
    const currentUserAgent = req.headers['user-agent'];
    
    if (tokenData.ipAddress !== currentIp || tokenData.userAgent !== currentUserAgent) {
      const suspiciousUseKey = `suspicious:${hashToken(refresh_token)}`;
      const suspiciousCount = await getAsync(suspiciousUseKey);
      
      if (suspiciousCount && parseInt(suspiciousCount) >= 3) {
        await revokeRefreshToken(refresh_token);
        await addToRevokedList(refresh_token);
        return res.status(400).json({ error: 'invalid_grant', error_description: 'Suspicious activity detected' });
      }
      
      if (!suspiciousCount) {
        await setAsync(suspiciousUseKey, '1', 'EX', 3600);
      } else {
        await redisClient.incr(suspiciousUseKey);
      }
    }
    
    const accessToken = generateSecureToken();
    
    await storeAccessToken(accessToken, {
      clientId: client_id,
      userId: tokenData.userId,
      scope: tokenData.scope,
      fingerprint: tokenData.fingerprint
    });
    
    await updateRefreshTokenUsage(refresh_token, tokenData);
    
    res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: ACCESS_TOKEN_EXPIRY,
      refresh_token: refresh_token,
      scope: tokenData.scope
    });
    
  } else {
    res.status(400).json({ error: 'unsupported_grant_type' });
  }
});

app.post('/revoke', async (req, res) => {
  const { token, token_type_hint, client_id, client_secret } = req.body;
  
  const client = await validateClient(client_id, client_secret);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  if (token_type_hint === 'refresh_token' || !token_type_hint) {
    await revokeRefreshToken(token);
    await addToRevokedList(token);
  }
  
  res.status(200).json({ success: true });
});

app.get('/userinfo', async (req, res) => {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token' });
  }
  
  const token = authHeader.substring(7);
  const hashedToken = hashToken(token);
  const tokenData = await getAsync(`access:${hashedToken}`);
  
  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token' });
  }
  
  const data = JSON.parse(tokenData);
  
  res.json({
    sub: data.userId,
    scope: data.scope
  });
});

app.post('/introspect', async (req, res) => {
  const { token, token_type_hint, client_id, client_secret } = req.body;
  
  const client = await validateClient(client_id, client_secret);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  const hashedToken = hashToken(token);
  let tokenData;
  let tokenType;
  
  if (token_type_hint === 'access_token' || !token_type_hint) {
    tokenData = await getAsync(`access:${hashedToken}`);
    tokenType = 'access_token';
  }
  
  if (!tokenData && (token_type_hint === 'refresh_token' || !token_type_hint)) {
    tokenData = await getAsync(`refresh:${hashedToken}`);
    tokenType = 'refresh_token';
  }
  
  if (!tokenData) {
    return res.json({ active: false });
  }
  
  const data = JSON.parse(tokenData);
  
  if (data.clientId !== client_id) {
    return res.json({ active: false });
  }
  
  const exp = tokenType === 'access_token' 
    ? Math.floor(Date.now() / 1000) + ACCESS_TOKEN_EXPIRY
    : Math.floor(data.createdAt / 1000) + REFRESH_TOKEN_EXPIRY;
  
  res.json({
    active: true,
    scope: data.scope,
    client_id: data.clientId,
    username: data.userId,
    token_type: tokenType,
    exp: exp,
    iat: Math.floor((data.createdAt || Date.now()) / 1000)
  });
});

